export default function Finance(){

const income=50000;

const expense=25000;

const profit=income-expense;

return(

<div style={{padding:'20px'}}>

<h2>Finance</h2>

<h3>Income : ₹{income}</h3>

<h3>Expense : ₹{expense}</h3>

<h3>Profit : ₹{profit}</h3>

</div>

)

}
